#include <bits/stdc++.h>
using namespace std;

const int N=370;

int n,m,sz[N];
long long f[N][N][N],h[N][N];
vector<int> g[N];

void Update(long long &x,long long y){
	x=(x>y?x:y);
}

void dfs(int x){
	sz[x]=1;
	f[x][0][1]=0;
	f[x][1][0]=1;
	for(int y:g[x]){
		dfs(y);
		for(int i=0;i<=sz[x]+sz[y];i++)
			for(int j=0;j<=sz[x]+sz[y];j++)
				h[i][j]=-1e18;
		for(int i=0;i<=sz[x];i++)
			for(int j=0;j<=sz[y];j++)
				for(int k=0;k<=sz[x];k++)
					for(int l=0;l<=sz[y];l++)
						Update(h[max(i,j)][k+l],f[x][i][k]+f[y][j][l]+max(i,j)-i);
		sz[x]+=sz[y];
		for(int i=0;i<=sz[x];i++)
			for(int j=0;j<=sz[x];j++)
				Update(h[i+1][j-1],h[i][j]+1);
		for(int i=0;i<=sz[x];i++)
			for(int j=0;j<=sz[x];j++)
				Update(f[x][i][j],h[i][j]);
	}
}

int main(){
	int T;
	scanf("%d",&T);
	while(T--){
		memset(f,0xcf,sizeof(f));
		scanf("%d%d",&n,&m);
		for(int i=2,p;i<=n;i++){
			scanf("%d",&p);
			g[p].push_back(i);
		}
		dfs(1);
		long long ans=-1e18;
		for(int i=0;i<=sz[1];i++)
			for(int j=0;j<=sz[1];j++)
				Update(ans,f[1][i][j]);
		for(int i=1;i<=n;i++)
			g[i].clear();
		printf("%lld\n",ans);
	}
	return 0;
}
